INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (123, 'Hawaii Five-0', 'Hawaii Five-0', 'Hawaii Five-0 is a contemporary take on the classic series about a new elite federalized task force whose mission is to wipe out the crime that washes up on the Islands'' sun-drenched beaches. Detective Steve McGarrett, a decorated Naval officer-turned-cop, returned to Oahu to investigate his father''s murder and stayed after Hawaii''s former governor persuaded him to head up the new team: his rules, no red tape and full blanket authority to hunt down the biggest "game" in town. Joining McGarrett is Detective Danny "Danno" Williams, a relocated ex-New Jersey cop - a working man in paradise who prefers skyscrapers to the coastline - but who''s committed to keeping the Islands safe for his young daughter; Chin Ho Kelly, an ex-Honolulu police detective and former protégé of McGarrett''s father who was wrongly accused of corruption; Dr. Max Bergman, the quirky coroner; Chin''s cousin, Kono Kalakaua, a beautiful and fearless native; and Captain Lou Grover, who formerly headed Hawaii''s SWAT unit. Joining them is Jerry Ortega, a former classmate of Chin''s and the Island''s local conspiracy theorist. The state''s brash FIVE-0 unit, who may spar and jest among themselves, remain determined to eliminate the seedy elements from the 50th state.', 7.7, '2010-09-20', 'https://static.tvmaze.com/uploads/images/original_untouched/213/532575.jpg', 'SHOW');
