INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (124, 'Hellsing', 'Hellsing', 'Hellsing is a 13-part anime based on the manga of the same name. The plot is significantly difficult to that of the the manga although the characters are the same. The show mainly focuses on the hellsing institute that houses the anti-hero named Alucard who swore loyalty to the Helsing family many years before. Alucard being the first ever vampire takes on a new apprentice named Sera''s.', 7.3, '2001-10-10', 'https://static.tvmaze.com/uploads/images/original_untouched/178/446544.jpg', 'SHOW');
