INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (125, 'Hellsing Ultimate', 'Hellsing Ultimate', 'Hellsing Ultimate, unlike the 13-part Hellsing series, follows the manga of the same name very closely. Alucard being the main protagonist and anti-hero/vampire. Hellsing Ultimate is a 10-part series of OVAs whereby Alucard turns Sera''s into a vampire. The main focus of the plot being on an enemy neo-nazi group.', 7.6, '2006-02-10', 'https://static.tvmaze.com/uploads/images/original_untouched/178/446780.jpg', 'SHOW');
