INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (126, 'Berserk', 'Berserk', 'Berserk is a 25-part anime set in a dark fantasy/horror environment whereby the series focuses on the main character guts; a lone swordman who later meets up with a group of mercenaries called the band of the hawk. The leader of this band holds a strange necklace called a behelit that will only lead to evil.', 8.1, '1997-10-07', 'https://static.tvmaze.com/uploads/images/original_untouched/396/991619.jpg', 'SHOW');
