INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (135, 'Intruders', 'Intruders', 'A contemporary, chilling, paranormal tale set in the moody Pacific Northwest, the series spins a fascinating and complex web of drama. As strange, apparently unrelated events start happening, multiple story-lines - a missing wife, an assassin covering his crimes, a child on the run - begin to intertwine to reveal a conspiracy that will forever change our understanding of human nature.', 7.2, '2014-08-23', 'https://static.tvmaze.com/uploads/images/original_untouched/126/316698.jpg', 'SHOW');
