INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (136, 'Z Nation', 'Z Nation', 'Z Nation starts three years after the zombie virus has gutted the country, a team of everyday heroes must transport the only known survivor of the plague from New York to California, where the last functioning viral lab waits for his blood. Although the antibodies he carries are the world''s last, best hope for a vaccine, he hides a dark secret that threatens them all. With humankind''s survival at stake, the ragtag band embarks on a journey of survival across three thousand miles of rusted-out post-apocalyptic America.', 7.2, '2014-09-12', 'https://static.tvmaze.com/uploads/images/original_untouched/170/426759.jpg', 'SHOW');
