INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (141, 'Outlander', 'Outlander', 'Outlander follows the story of Claire Randall, a married combat nurse from 1945 who is mysteriously swept back in time to 1743, where she is immediately thrown into an unknown world where her life is threatened. When she is forced to marry Jamie, a chivalrous and romantic young Scottish warrior, a passionate affair is ignited that tears Claire''s heart between two vastly different men in two irreconcilable lives.The Outlander series, adapted from Diana Gabaldon''s international best-selling books, spans the genres of romance, science fiction, history and adventure into one epic tale.', 7.9, '2014-08-09', 'https://static.tvmaze.com/uploads/images/original_untouched/597/1493736.jpg', 'SHOW');
