INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (144, 'Forever', 'Forever', 'Doctor Henry Morgan, New York City''s star medical examiner, has a secret. He doesn''t just study the dead to solve criminal cases, he does it to solve the mystery that has eluded him for 200 years - the answer to his own inexplicable immortality. This long life has given Henry remarkable observation skills which impresses his new partner, Detective Jo Martinez. Each week, a new case and their budding friendship will reveal layers of Henry''s long and colorful past. Only his best friend and confidant, Abe knows Henry''s secret.', 8.1, '2014-09-22', 'https://static.tvmaze.com/uploads/images/original_untouched/0/383.jpg', 'SHOW');
