INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (145, 'Witches of East End', 'Witches of East End', 'Based on Melissa de la Cruz''s best-selling novel, Witches of East End centers on the mysterious Beauchamp family who live in the secluded seaside town of East End. Free-spirited artist Joanna Beauchamp is the mother of wild-child bartender Freya and shy librarian Ingrid, who are both gifted -- and cursed -- with a magic birthright, of which they are unaware. Freya notices bizarre occurrences in her life when she inexplicably finds herself drawn to the troubled brother of her wealthy fiance. But it isn''t until Joanna''s estranged sister appears with a warning that could change the family''s fate that the matriarch must reveal to her daughters that they are immortal witches with untapped powers, a revelation that turns their small-town life upside down.', 7.5, '2013-10-06', 'https://static.tvmaze.com/uploads/images/original_untouched/0/392.jpg', 'SHOW');
