INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (147, 'Brooklyn Nine-Nine', 'Brooklyn Nine-Nine', 'Brooklyn Nine-Nine is an ensemble comedy about a talented-but-carefree detective, a by-the-book police captain and their precinct colleagues. While based in the workplace, Brooklyn Nine-Nine is not really about the job – it''s about the men and women behind the badge.', 8.1, '2013-09-17', 'https://static.tvmaze.com/uploads/images/original_untouched/402/1007484.jpg', 'SHOW');
