INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (150, 'How to Get Away with Murder', 'How to Get Away with Murder', 'The brilliant, charismatic and seductive Professor Annalise Keating gets entangled with four law students from her class, How to Get Away with Murder. Little do they know that they will have to apply what they learned to real life, in this masterful, sexy, suspense-driven legal thriller.', 7.5, '2014-09-25', 'https://static.tvmaze.com/uploads/images/original_untouched/212/531512.jpg', 'SHOW');
