INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (152, 'Legends', 'Legends', 'Sean Bean stars in Legends, a suspense-filled drama based on the award-winning book by master spy novelist Robert Littell. Bean plays Martin Odum, an undercover agent working for the FBI''s Deep Cover Operations (DCO) division. Martin has the uncanny ability to transform himself into a completely different person for each job. But he begins to question his own identity when a mysterious stranger suggests that Martin isn''t the man he believes himself to be.', 7.5, '2014-08-13', 'https://static.tvmaze.com/uploads/images/original_untouched/36/92018.jpg', 'SHOW');
