INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (153, 'Red Band Society', 'Red Band Society', 'What if a hospital was your high school, boarding school and summer camp rolled into one? What if it was the place where you fell in love for the first time and made friendships that lasted a lifetime? And what if it was all weirdly hilarious and the most fun you ever had in your entire life? This is the world of Red Band Society.', 7.7, '2014-09-17', 'https://static.tvmaze.com/uploads/images/original_untouched/0/441.jpg', 'SHOW');
