INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (154, 'Chicago P.D.', 'Chicago P.D.', 'District 21 of the Chicago Police Department is made up of two distinctly different groups. There are the uniformed cops who patrol the beat and go head to head with the city''s street crimes. And there''s the Intelligence Unit, the team that combats the city''s major offenses - organized crime, drug trafficking, high profile murders and beyond. These are their stories.', 8.0, '2014-01-08', 'https://static.tvmaze.com/uploads/images/original_untouched/590/1475641.jpg', 'SHOW');
