INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (159, 'Orphan Black', 'Orphan Black', 'Orphan Black is about Sarah, an outsider and orphan whose life changes dramatically after witnessing the suicide of a woman, "Beth", who looks just like her. Sarah takes her identity, her boyfriend and her money. But instead of solving her problems, the street-smart chameleon is thrust headlong into a kaleidoscopic mystery. She makes the dizzying discovery that she and the dead woman are clones... but are they the only ones? Sarah quickly finds herself caught in the middle of a deadly conspiracy, racing to find answers.', 8.6, '2013-03-30', 'https://static.tvmaze.com/uploads/images/original_untouched/484/1210257.jpg', 'SHOW');
