INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (165, 'Grey''s Anatomy', 'Grey''s Anatomy', 'The doctors of Grey Sloan Memorial Hospital deal with life-or-death consequences on a daily basis -- it''s in one another that they find comfort, friendship and, at times, more than friendship. Together they''re discovering that neither medicine nor relationships can be defined in black and white. Real life only comes in shades of grey.', 7.6, '2005-03-27', 'https://static.tvmaze.com/uploads/images/original_untouched/600/1501061.jpg', 'SHOW');
