INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (166, 'Castle', 'Castle', 'Castle follows Rick Castle who is one of the world''s most successful crime authors. But when his rock star lifestyle isn''t enough, this bad boy goes looking for new trouble and finds it working with smart, beautiful Detective Kate Beckett. Inspired by her professional record and intrigued by her buttoned-up personality, Castle''s found the model for his bold new character whether she likes it or not. Now with the mayor''s permission, Castle is helping solve crime with his own twist.', 8.2, '2009-03-09', 'https://static.tvmaze.com/uploads/images/original_untouched/13/34761.jpg', 'SHOW');
