INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (174, 'Sons of Anarchy', 'Sons of Anarchy', 'Sons of Anarchy is an American television drama series created by Kurt Sutter, about the lives of a close-knit outlaw motorcycle club operating in Charming, a fictional town in California''s Central Valley. The show centers on protagonist Jackson "Jax" Teller (Charlie Hunnam), initially the vice president of the club, who begins questioning the club and himself.', 8.3, '2008-09-03', 'https://static.tvmaze.com/uploads/images/original_untouched/495/1239905.jpg', 'SHOW');
