INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (176, 'The Mysteries of Laura', 'The Mysteries of Laura', 'Laura Diamond is a brilliant NYPD homicide detective who balances her "Columbo" day job with a crazy family life that includes two unruly twin boys and a soon-to-be ex-husband - also a cop - who just can''t seem to sign the divorce papers. Between cleaning up after her boys and cleaning up the streets, she''d be the first to admit she has her "hot mess" moments in this hilariously authentic look at what it really means to be a working mom today. Somehow, she makes it all work with the help of her sexy and understanding partner, and things becomes even more complicated when her husband becomes her boss at the precinct. For Laura, every day is a high-wire balancing act.', 7.3, '2014-09-17', 'https://static.tvmaze.com/uploads/images/original_untouched/0/568.jpg', 'SHOW');
