INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (182, 'Family Guy', 'Family Guy', 'Family Guy follows Peter Griffin the endearingly ignorant dad, and his hilariously offbeat family of middle-class New Englanders in Quahog, RI. Lois is Peter''s wife, a stay-at-home mom with no patience for her family''s antics. Then there are their kids: 18-year-old Meg is an outcast at school and the Griffin family punching bag; 13-year-old Chris is a socially awkward teen who doesn''t have a clue about the opposite sex; and one-year-old Stewie is a diabolically clever baby whose burgeoning sexuality is very much a work in progress. Rounding out the Griffin household is Brian the family dog and a ladies'' man who is one step away from AA.', 7.5, '1999-01-31', 'https://static.tvmaze.com/uploads/images/original_untouched/609/1523259.jpg', 'SHOW');
