INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (186, 'Unforgettable', 'Unforgettable', 'Unforgettable follows Carrie Wells, an enigmatic former police detective with a rare condition that makes her memory so flawless that every place, every conversation, every moment of joy and every heartbreak is forever embedded in her mind. It''s not just that she doesn''t forget anything - she can''t; except for one thing: the details that would help solve her sister''s long-ago murder. Carrie has tried to put her past behind her, but she''s unexpectedly reunited with her ex-boyfriend and partner, NYPD Detective Al Burns when she consults on a homicide case.', 7.5, '2011-09-20', 'https://static.tvmaze.com/uploads/images/original_untouched/0/663.jpg', 'SHOW');
