INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (189, 'A to Z', 'A to Z', 'This is the A to Z story of Andrew and Zelda - a pair that almost wasn''t - and all that happened from the day they met. Andrew has always been a secret romantic... not above crooning to Celine Dion while driving to work, with dreams of finding "the one." He imagines her to be just like that shimmering beauty he spotted that night in that silver dress at that concert two years ago. Zelda, having grown up with a hippie mom who believed the universe would provide for everything, rebelled into a no-nonsense practical lawyer who prefers the control of online dating. But when a computer glitch sends her a total mismatch, she''s asked to come in for an interview at the Internet dating site where Andrew works, and this is where it all begins. Andrew and Zelda meet for the first time and despite their differences, sparks fly. She thinks it''s chance. He thinks it''s fate. After all, he''s convinced she''s the shimmering girl in the silver dress. Is it true love forever or just a detour in destiny?', 6.7, '2014-10-02', 'https://static.tvmaze.com/uploads/images/original_untouched/0/679.jpg', 'SHOW');
