INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (192, 'Falling Skies', 'Falling Skies', 'The series tells the story of the aftermath of a global invasion by several races of extraterrestrials that neutralizes the world''s power grid and technology, quickly destroys the combined militaries of all the world''s countries, and apparently kills over 90% of the human population within a few days.', 7.7, '2011-06-19', 'https://static.tvmaze.com/uploads/images/original_untouched/498/1246070.jpg', 'SHOW');
