INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (195, 'Scandal', 'Scandal', 'Everyone has secrets… and Olivia Pope has dedicated her life to protecting and defending the public images of the nation''s elite by keeping those secrets under wraps. Pope''s team are at the top of their game when it comes to getting the job done for their clients, but it becomes apparent that these "gladiators in suits", who specialize in fixing the lives of other people, have trouble fixing those closest at hand -- their own.', 7.8, '2012-04-05', 'https://static.tvmaze.com/uploads/images/original_untouched/303/758518.jpg', 'SHOW');
