INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (196, 'America''s Next Top Model', 'America''s Next Top Model', 'Created by supermodel Tyra Banks, America''s Next Top Model follows a group of young women of various backgrounds, shapes and sizes who live together in a loft and vie for a modeling contract. The show exposes the transformation of everyday young women into potentially fierce supermodels, with participants facing weekly tests that determine who can make the cut. With mentoring by supermodel Tyra Banks and exposure to high-profile fashion-industry gurus, the finalists compete in a highly accelerated modeling boot camp--a crash course to supermodel fame.', 5.5, '2003-05-20', 'https://static.tvmaze.com/uploads/images/original_untouched/147/369365.jpg', 'SHOW');
