INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (198, 'The Good Wife', 'The Good Wife', 'The Good Wife follows Alicia Florrick, a wife and mother who boldly assumes full responsibility for her family and re-enters the workforce after her husband''s very public sex and political corruption scandal lands him in jail. Pushing aside the betrayal and crushing public humiliation caused by her husband Peter, Alicia starts over by pursuing her original career as a defense attorney.', 8.1, '2009-09-22', 'https://static.tvmaze.com/uploads/images/original_untouched/59/148162.jpg', 'SHOW');
