INSERT INTO content (content_id, originaltitle, title, description, rating, releasedate, thumbnail, type) VALUES (199, 'Boardwalk Empire', 'Boardwalk Empire', 'As the country struggles to cope with the Great Depression and the end of Prohibition looms, Nucky Thompson looks to legitimize himself through alliances with liquor producers, while rivals Lucky Luciano and Meyer Lansky seek to consolidate their power in the wake of Arnold Rothstein''s death and eliminate all competition - by any means necessary on Boardwalk Empire.', 8.4, '2010-09-19', 'https://static.tvmaze.com/uploads/images/original_untouched/405/1012589.jpg', 'SHOW');
