-- =========================================================
-- CONTENT_HAS_LIST (put some content into lists)
-- =========================================================

SELECT c.content_id, l.list_id
FROM lists l
JOIN LATERAL (
  SELECT content_id FROM content ORDER BY random() LIMIT 30
) c ON true
ON CONFLICT DO NOTHING;

-- =========================================================
-- REVIEWS (profiles rate movies/shows)
-- =========================================================

SELECT
  (ARRAY['Amazing','Good','Okay','Not great','Masterpiece'])[1+(random()*4)::int],
  (1 + (random()*4)::int)::smallint,
  (ARRAY[
    'Really enjoyed it.',
    'Pretty solid overall.',
    'Could be better.',
    'Not my taste, but fine.',
    'One of the best I have seen.'
  ])[1+(random()*4)::int],
  NOW() - (random()*120 || ' days')::interval,
  p.profile_id,
  c.content_id::int
FROM (SELECT profile_id FROM profile) p
JOIN LATERAL (
  SELECT content_id FROM content ORDER BY random() LIMIT 40
) c ON true;

